  ('9777e9cb-471c-5d37-93d7-ca804850b181', '62c13512-9026-58a5-ae34-ca7fe0e1061a', 'Laudo de Controle de Material de Acabamento e Revestimento', 'grupo', 5),
  ('316a3e74-8d31-5168-8af8-5a44c25c19ca', '62c13512-9026-58a5-ae34-ca7fe0e1061a', 'Notas Fiscais', 'grupo', 6),
  ('007d108a-60ed-5409-82e1-b681f4e83e09', '62c13512-9026-58a5-ae34-ca7fe0e1061a', 'Outros', 'outros', 7)
INSERT INTO public.checklist_itens_modelo (id, grupo_id, numero_original, descricao, complemento, tipo, avaliavel, ordem)
VALUES
  ('5677c0d3-5285-585f-b57e-4ae6c70a0ff4', '237850e0-9737-56cf-97e1-898d45727f30', '1', 'Verificar se a localizacao dos arruamentos ou vias de acesso que sao limitrofes a edificacao estao de acordo com o projeto aprovado (planta de localizacao e planta de situacao).', NULL, 'item', true, 1),
  ('b1d939f2-401c-524f-8c07-244ccfff94e9', '24bf3f4a-146f-522f-a1cb-459533c1b6f4', '1', 'Verificar se os arruamentos ou vias de acesso que sao limitrofes a edificacao possuem altura livre minima de 4,50 m e estao de acordo com o projeto aprovado (planta de localizacao e planta de situacao).', NULL, 'item', true, 1),
  ('ed8528a5-f712-56c7-976a-0ccc0e726cad', '24bf3f4a-146f-522f-a1cb-459533c1b6f4', '2', 'Verificar se os arruamentos ou vias de acesso que sao limitrofes a edificacao possuem largura minima de 4,00 m e estao de acordo com o projeto aprovado (planta de localizacao e planta de situacao).', NULL, 'item', true, 2),
  ('7ac48531-a7b4-5965-a4fe-2f6f1982db6e', '24bf3f4a-146f-522f-a1cb-459533c1b6f4', '3', 'Verificar, para condominios de casas e edificacoes, se a guarita de acesso de veiculos ou outros acessos subterraneos ao interior destes condominios possuem altura minima de 4,5 m conforme indicado em projeto.', NULL, 'item', true, 3),
  ('cddd8a60-3ba4-5ab2-960e-ab64cf474f62', '24bf3f4a-146f-522f-a1cb-459533c1b6f4', '4', 'Verificar, para condominios de casas e edificacoes, se a guarita de acesso de veiculos ou outros acessos subterraneos ao interior destes condominios possuem largura minima de 4,0 m conforme indicado em projeto.', NULL, 'item', true, 4),
  ('49c8cb8a-ee15-520d-a964-177d9eda4587', '7001ce6c-a7f5-548a-ae63-0ab92c602b70', '1', 'Verificar a inexistencia de qualquer abertura entre as unidades compartimentadas que nao esteja prevista em projeto.', NULL, 'item', true, 1),
  ('abb94c77-0b02-5f4a-bd2c-af6239325e46', '7001ce6c-a7f5-548a-ae63-0ab92c602b70', '2', 'Verificar, caso haja abertura permanente (ex.: correias transportadoras), que esta possua area maxima de 1,5 m2 com protecao de cortina d''agua conforme indicado em projeto.', NULL, 'item', true, 2),
  ('5e624ebc-6a71-5eb5-8a79-0429ed79b1b4', 'b6c27c10-a8b6-5b16-ae6d-8826f41c6bd0', '1', 'Verificar a integridade da parede de compartimentacao. (Nao pode haver rachaduras ou pontos que viciem a capacidade suas carateristicas de compartimentacao)', NULL, 'item', true, 1),
  ('89623b1c-4c26-5105-90e7-4a1dbc1a8c6c', 'b6c27c10-a8b6-5b16-ae6d-8826f41c6bd0', '2', 'Verificar, quando couber, se a parede de compartimentacao se estende no fechamento ate o teto, como tambem, nas extensoes verticais e de fachada conforme indicado em projeto.', NULL, 'item', true, 2),
  ('4c5ee2af-7f00-5e9a-9235-6a3e0c8b20e7', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '1', 'Verificar se a posicao das PCF''s que interliga as unidades compartimentadas esta conforme indicada em projeto.', NULL, 'item', true, 1),
  ('c7a90439-c248-5720-90df-8333ac709df1', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '2', 'Verificar se a largura das PCF''s estao conforme indicado em planta.', NULL, 'item', true, 2),
  ('706d9861-400b-5b8d-bac9-35273d854af4', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '3', 'Verificar se as PCF''s estao pintadas na cor vermelha.', NULL, 'item', true, 3),
  ('38648383-2cd2-596f-9e12-1e28874f1a80', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '4', 'Verificar se as PCF''s estao abrindo no sentido conforme indicado projeto.', NULL, 'item', true, 4),
  ('cd9add82-c832-5bdb-9c31-31eba428a206', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '5', 'Verificar se a especificacao das PCF''s atende ao criterio de TRRF conforme indicado em projeto. (Tal verificacao e indicada na parte posterior da folha da PCF com a respectiva certificacao do produto).', NULL, 'item', true, 5),
  ('7fb5db0f-fdfc-5bf9-887f-b9114dddf260', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '6', 'Verificar se as PCF''s estao indicadas com sinalizacao de emergencia "PORTA CORTA FOGO- MANTENHA FECHADA" - Sinalizacao de Emergencia M4 - conforme parte III da IT 05.', NULL, 'item', true, 6),
  ('6fbeafc0-1f2a-5329-a5e8-b7f8df324bb9', 'ca2e32a7-de78-5c5e-8fc2-aa9442ae269f', '7', 'Realizar o teste de abertura e fechamento de todas as PCF''s, verificando sua integridade e capacidade de vedacao. Todas as PCF''s devem possuir o mecanismo de fechamento mecanico.', NULL, 'item', true, 7),
  ('736668bf-0417-5833-8130-56cc815e62dc', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '1', 'Verificar se a posicao dos Vedadores Corta-Fogo que interliga as unidades compartimentadas esta conforme indicado em projeto.', NULL, 'item', true, 1),
  ('c0c1613b-c741-5ff6-8bbf-45a1e5a78476', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '2', 'Verificar se a largura dos Vedadores Corta-Fogo estao conforme indicada em planta.', NULL, 'item', true, 2),
  ('a6bcf41c-dc91-5d9c-9da4-60cfa93ded3d', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '3', 'Verificar se os Vedadores Corta-Fogo estao pintados na cor vermelha.', NULL, 'item', true, 3),
  ('fb5edac9-3f4d-5cb9-9055-75efbc1406f7', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '4', 'Verificar se as caracteristicas dos Vedadores Corta-Fogo estao conforme indicadas em projeto. (Caracteristicas: - Simples ou dupla. - Uma ou duas folhas).', NULL, 'item', true, 4),
  ('79a6f2ea-4fee-55d7-83d9-83577e2f22c0', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '5', 'Verificar se a especificacao dos Vedadores Corta-Fogo atende ao criterio de TRRF conforme indicado em projeto. (Tal verificacao e indicada na parte posterior da folha dos Vedadores Corta-Fogo com a respectiva certificacao do produto).', NULL, 'item', true, 5),
  ('05ef70bc-af53-57fb-8813-ca2867edc8a1', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '6', 'Localizar, quando couber, o elemento termo sensivel nos Vedadores Corta-Fogo de forma a garantir o seu fechamento automatico.', NULL, 'item', true, 6),
  ('0a622a5f-c011-593f-92e6-6feccf0dadc3', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '7', 'Testar, quando couber, o sistema de deteccao responsavel pelo fechamento automatico do vedador, seu acionamento manual por meio da central e as sinalizacoes do status do equipamento na central do sistema.', NULL, 'item', true, 7),
  ('cc6dcab3-50e2-57d7-b3ee-7234ff3d84ad', 'fa7b10f8-597f-5c78-ae0d-52ef23eddb47', '8', 'Realizar o teste de abertura e fechamento de todos os Vedadores Corta- Fogo de forma manual, verificando sua integridade e capacidade de vedacao.', NULL, 'item', true, 8),
  ('620767bc-a414-59a3-8364-92d6ece42d15', 'd37afe5e-5330-55dc-a05e-ba231ef11e5b', '1', 'Verificar, quando houver, se as instalacoes de servico estao devidamente seladas por elemento resistente ao fogo entre as unidades de compartimentacao. (Para os tubos plasticos com diametro interno superior a 40 mm e obrigatoria a instalacao de registros corta-fogo ou selagem especial que garanta a vedacao do orificio deixado pelo tubo ao ser consumido pelo fogo).', NULL, 'item', true, 1),
  ('7de3b7c4-7b52-515e-8da3-3994916ae2b1', 'd37afe5e-5330-55dc-a05e-ba231ef11e5b', '2', 'Verificar a integridade da selagem e, havendo periodicidade de manutencao, verificar se a validade da aplicacao do material esta em conformidade com a especificacao.', NULL, 'item', true, 2),
  ('48a943e8-704c-5146-b4b6-a26668273588', 'd36a73ef-4243-5dff-aae6-5ff1bc40791b', '1', 'Verificar, quando houver, se as instalacoes de servico estao devidamente vedadas por elemento resistente ao fogo entre as unidades de compartimentacao (Para os tubos plasticos com diametro interno superior a 40 mm e obrigatoria a instalacao de registros corta-fogo).', NULL, 'item', true, 1),
  ('e131ee69-ad4a-5fd7-ad3d-6a62bccaae6c', 'f40de4fa-fbe3-5f62-8002-182a19cce6ee', '1', 'Possibilidade 01: Verificar se os dutos de ventilacao, ar condicionado e exaustao possuem os devidos registros corta-fogo e adequada selagem corta fogo no entorno do duto entre as unidades compartimentadas.', NULL, 'item', true, 1),
  ('b3cbf3e6-cb85-5be9-9ad2-2db5d4fa9d03', 'f40de4fa-fbe3-5f62-8002-182a19cce6ee', '2', 'Possibilidade 02: Verificar se os dutos de ventilacao, ar condicionado e exaustao possuem a devida selagem corta fogo em toda a sua extensao sendo que os registros corta-fogo devem ser instalados nas saidas de ar.', NULL, 'item', true, 2),
  ('f500d37a-fd1c-5570-a7c5-af17f0a49763', '0bf58954-7cce-53f9-a05e-48af50a84c3f', '1', 'Possibilidade 01: Verificar para coberturas combustiveis (telhado) se a parede de compartimentacao se estende a no minimo 1m acima da linha de cobertura conforme indicado em projeto.', NULL, 'item', true, 1),
  ('2ccfefb3-e508-53ab-87b2-7ffab38964fd', '0bf58954-7cce-53f9-a05e-48af50a84c3f', '2', 'Possibilidade 02: Verificar, caso a cobertura seja combustivel (telhado), se esta possui um distanciamento minimo de material incombustivel de 1m para cada lado da divisoria de compartimentacao conforme indicado em projeto.', NULL, 'item', true, 2),
  ('2b16bb9a-6d57-5357-9537-35ac73147aa3', 'b38af241-4197-5c7f-8853-08be7bc931e4', '1', 'Possibilidade 01: Verificar se, as aberturas situadas na mesma fachada em lados opostos da divisoria de compartimentacao, estao afastadas horizontalmente entre si por um trecho de parede com 2 metros de extensao devidamente consolidada na mesma divisoria com mesma caracteristica de resistencia ao fogo conforme indicado em projeto.', NULL, 'item', true, 1),
  ('af52e946-2166-5e07-8191-106e269beaa7', 'b38af241-4197-5c7f-8853-08be7bc931e4', '2', 'Possibilidade 02: Verificar se a divisoria de compartimentacao se prolonga na fachada externa com no minimo 0,90 m, conforme indicado em projeto.', NULL, 'item', true, 2),
  ('02db5fe5-36f8-5bff-8169-f3723f222a49', '25e79dea-29b3-55a7-8142-6ca33e46ac90', '1', 'Verificar se nao houve alguma alteracao estrutural na fachada da edificacao que altere as caracteristicas de compartimentacao do envoltorio conforme Projeto Tecnico em conformidade com as normas vigentes.', NULL, 'item', true, 1),
  ('47a8205e-cce7-591d-9213-4f36c7400a0f', '8972709d-38bc-5541-8a89-ff542a971e66', '1', 'Verificar, quando possivel, se entre a fachada de vidro e os parapeitos, vigas ou prolongamentos dos entrepisos destas fachadas esta instalado os elementos de separacao (vedacao perimetral) que possibilite a compartimentacao vertical da edificacao.', NULL, 'item', true, 1),
  ('29a99ab0-0e59-50d6-8d9a-2d7551de7978', 'a83e0a30-97c6-55d1-9cae-2dfdfd6ad147', '1', 'Verificar a inexistencia de qualquer abertura nao prevista da escada de emergencia para os ambientes adjacentes conforme indicado em projeto.', NULL, 'item', true, 1),
  ('21efddd6-92be-549f-b8af-e7af9150024a', 'a83e0a30-97c6-55d1-9cae-2dfdfd6ad147', '2', 'Cumprir checklist especifico da escada de seguranca.', NULL, 'item', true, 2),
  ('da18a445-7a33-5d2e-a19f-4317fe005980', '37aea532-4883-5874-89df-6e0ce5bdfa70', '1', 'Verificar integridade da vedacao das paredes corta-fogo compartimentacao dos pocos destinados a elevadores e montacarga em suas aberturas e nas conexoes com as lajes.', NULL, 'item', true, 1),
  ('b43607db-1bcc-5e44-a03e-f7a777ef7b7f', '37aea532-4883-5874-89df-6e0ce5bdfa70', '2', 'Verificar a integridade dos vedadores para chamas (portas do elevador PRF) nas aberturas dos elevadores.', NULL, 'item', true, 2),
  ('887e9acb-f06e-5cd7-9f88-6dbb3ab1ed3a', '16733cb3-53a7-59a4-98fa-ce38649f0f27', '1', 'Verificar se as prumadas destinadas a instalacoes de servico estao devidamente seladas por elemento resistente ao fogo nos entrepisos conforme indicado em projeto (para os tubos plasticos com diametro interno superior a 40mm e obrigatoria a instalacao de registros corta-fogo ou selagem especial que garanta a vedacao do orificio deixado pelo tubo ao ser consumido pelo fogo).', NULL, 'item', true, 1),
  ('cc8ff059-a822-5f7d-9ba9-bd63f4eaeb5f', '16733cb3-53a7-59a4-98fa-ce38649f0f27', '2', 'Verificar a integridade da selagem e, havendo periodicidade de manutencao, verificar se a validade da aplicacao do material esta em conformidade com a especificacao.', NULL, 'item', true, 2),
  ('db80e1f8-2872-538b-ad11-79c6029a76e2', 'f656c139-412d-57e6-8c07-fe3ef863421a', '1', 'Verificar, quando couber, se o elemento corta-fogo destinado a protecao das prumadas destinadas a instalacoes de servico estao com a manutencao em dia conforme sua especificacao. (Selos, Registros corta- fogo, etc.)', NULL, 'item', true, 1),
  ('fc0f4968-3e2d-5e23-8ce1-65c86b290c30', '5f2f461b-1dbd-5835-a1a7-bf3146c91fc3', '1', 'Verificar, sendo o caso, se os dutos de ventilacao possuem os registros corta fogo nos entre pisos ou nas saidas para os andares em comunicacao para o restante do pavimento.', NULL, 'item', true, 1),
  ('b662b600-8ecd-59bd-8af9-3413f069d429', '0048149f-c5b6-5873-bfd1-f3b183a36705', '1', 'Verificar se as condicoes dos atrios e outros mecanismos (ex: cortinas de compartimentacao vertical), quando houver, estejam protegidas e dimensionadas conforme indicado em projeto.', NULL, 'item', true, 1),
  ('860143fb-b5c1-5eae-9f35-ab4cccb992d1', 'b9bb7225-3ea1-5542-8d50-fd5d40021683', '1', 'Verificar se houve mudanca do projeto arquitetonico de forma a alterar as condicoes das saidas de emergencia.', NULL, 'item', true, 1),
  ('262c9d10-d480-59d5-80f6-ccaee2d4648f', '66b8a6df-b37b-514f-8f14-7e4b0c7c308b', '1', 'Verificar se o piso da escada e regular e antiderrapante.', NULL, 'item', true, 1),
  ('7e44e203-e975-5355-9d0d-eeaf32c42317', '51c18737-e28a-5d6b-9e47-ee00a977a603', '1', 'Verificar a integridade do corrimao - material utilizado - e sua fixacao.', NULL, 'item', true, 1),
  ('5e5ff1e7-9dc0-5ec0-b3d9-75ad44c9f223', '51c18737-e28a-5d6b-9e47-ee00a977a603', '2', 'Verificar se o caminhamento interno do corrimao e continuo em toda a sua extensao da escada.', NULL, 'item', true, 2),
  ('0d984575-be46-59f6-892d-d01c1f522110', '51c18737-e28a-5d6b-9e47-ee00a977a603', '3', 'Verificar se a altura de instalacao do corrimao esta entre 80 - 92 cm.', NULL, 'item', true, 3),
  ('f35496ce-c18e-59c6-8550-32817157cfc4', '812e7a62-4c1e-5bce-ab41-bd42c7f0c829', '1', 'Verificar a integridade do guarda-corpo - material utilizado - e sua fixacao.', NULL, 'item', true, 1),
  ('25731a4e-04b4-5941-a118-702a11b23cce', '812e7a62-4c1e-5bce-ab41-bd42c7f0c829', '2', 'Verificar a altura do guarda-corpo e maior ou igual a 1,10 m.', NULL, 'item', true, 2),
  ('ac5de876-6cd4-5c47-8957-e10fb756eef7', '812e7a62-4c1e-5bce-ab41-bd42c7f0c829', '3', 'Verificar, quando for o caso, se os afastamentos entre as longarinas possuem distancia minima de 15 cm.', NULL, 'item', true, 3),
  ('5bfd8213-368d-5525-9324-587c53491799', '812e7a62-4c1e-5bce-ab41-bd42c7f0c829', '4', 'Verificar, no caso de guarda-corpo de vidro, se sao do tipo laminado ou aramado.', NULL, 'item', true, 4),
  ('8342f0fb-2a00-5568-ba45-9de581236afb', '4b2df026-09c7-56c8-bade-ae307053b43d', '1', 'Verificar para as unidades autonomas com capacidade de publico superior a 50 pessoas se a portas abrem no sentido de fuga. Nota: A largura da porta devera atender ao publico da unidade autonoma.', NULL, 'item', true, 1),
  ('2b30c744-97cd-52ad-bc3e-8f007db819a9', '4b2df026-09c7-56c8-bade-ae307053b43d', '2', 'Verificar para as unidades autonomas com capacidade de publico superior a 200 pessoas se as portas possuem barra antipanico.', NULL, 'item', true, 2),
  ('dfe30834-b250-5ac5-ade9-c00f8eb4e58b', '26ae31ca-ba60-5c77-b599-1091ceb337f4', '1', 'Verificar Checklist especifico de Sinalizacao de Emergencia.', NULL, 'item', true, 1),
  ('bdb5312d-f6df-5d16-bd7b-48af723df7d1', '11a0472b-5185-5069-8e6e-c126290a333e', '1', 'Verificar se nao houve alteracao do projeto arquitetonico de forma a alterar as condicoes das saidas de emergencia.', NULL, 'item', true, 1),
  ('56141a92-e0ea-521c-963f-1c44e65c7699', '9b4a79a0-10d4-5456-b1fa-cfcd4c503577', '1', 'Verificar se o piso da escada e regular e antiderrapante.', NULL, 'item', true, 1),
  ('6cfa4170-7361-5236-aae7-9f7b82b09550', '9b4a79a0-10d4-5456-b1fa-cfcd4c503577', '2', 'Verificar se todas as portas que acessam a EEP sao PCF P-60.', NULL, 'item', true, 2),
  ('9704e964-7d56-5159-8f0b-b4ddad2b73ab', 'b45996b2-8e55-524d-b0c1-d6ee0d6f29f1', '1', 'Verificar se a instalacao do Alcapao de Alivio esta conforme indicada em planta - ultimo pavimento.', NULL, 'item', true, 1),
  ('c7a62ee4-be12-5da4-b43a-e3d1011c6d7a', '7370fc62-a531-5c0f-988e-077ac57d0787', '1', 'Verificar se as posicoes da janela de ventilacao, em todos os pavimentos, estao conforme indicadas em planta.', NULL, 'item', true, 1),
  ('69a7d951-7a69-5839-9b75-4fc13ba408af', '690f4611-1a95-5505-8a23-df162918afd0', '1', 'Verificar se a posicao da ventilacao permanente inferior (VPI) esta conforme indicada em planta - no pavimento terreo.', NULL, 'item', true, 1),
  ('58bb4e4a-3282-5fc4-9bae-51e5c0510809', 'b03c73ef-3890-5fcb-9478-f0f56952fb3c', '1', 'Verificar a integridade do corrimao - material utilizado - e sua fixacao.', NULL, 'item', true, 1),
  ('891d6c06-86d7-5307-883f-9e10f0b0571a', 'b03c73ef-3890-5fcb-9478-f0f56952fb3c', '2', 'Verificar se o corrimao do caminhamento interno e continuo em toda a extensao da caixa de escada, inclusive no patamar.', NULL, 'item', true, 2),
  ('f06b0f5b-51a4-5e64-a697-c3152dd65d10', 'b03c73ef-3890-5fcb-9478-f0f56952fb3c', '3', 'Verificar se o corrimao que auxilia o caminhamento externo da caixade escada e continuo em toda a sua extensao exceto nas proximidadesda PCF''s P-60. Nota: Neste caso o corrimao tem que exceder em no minimo 20 cm a chegada do patamar sendo seu termino curvado para o interior.', NULL, 'item', true, 3),
  ('771428b0-24d9-52ee-9fc3-71cca28c9104', '721fda42-9f93-578f-ba1f-f90e70d6c347', '1', 'Verificar se todos os acessos a descarga sao mediante PCF P-60.', NULL, 'item', true, 1),
  ('be6c5b77-69d8-5fe9-b9e7-8eb7edee9a36', '721fda42-9f93-578f-ba1f-f90e70d6c347', '2', 'Verificar se as ocupacoes inseridas na descarga conferem com o projeto aprovado.', NULL, 'item', true, 2),
