  ('4172ad63-2d6e-5731-b1d1-b52b4cc51778', '53b2b69e-6cc8-58f1-80bb-6ef508007334', '9', 'Verificar se o sistema mantem iluminacao constante por no minimo 15 minutos com todas as luminarias em funcionamento.', NULL, 'item', true, 9),
