  ('4b1007d5-bf17-50bc-b822-23fda3cabf83', '7826096d-f2fe-5ea5-a9e3-722245c2e37b', '3', 'Exigira nao existencia de materiais combustiveis no local do GMG, exceto o tanque-combustivel.', NULL, 'item', true, 3),
  ('1a453b90-cad5-5add-8f62-313c24636dfe', '7826096d-f2fe-5ea5-a9e3-722245c2e37b', '4', 'Verificar se o painel de controle esta na mesma sala do GMG.', NULL, 'item', true, 4),
