  ('43ca4f57-0b53-5718-a134-8f3757ad3ea5', '7826096d-f2fe-5ea5-a9e3-722245c2e37b', '6', 'Verificar se GMG possui dreno para escoamento de oleos e liquidos lubrificantes.', NULL, 'item', true, 6),
  ('56a55385-dd6f-59e0-a741-15a0c49213e9', '7826096d-f2fe-5ea5-a9e3-722245c2e37b', '7', 'Verificar se a tensao de saida do GMG para o sistema de iluminacao de emergencia possui alimentacao inferior a 30 Vcc. Nota: Locais compartimentados para escoamento de pessoas e livres de materiais combustiveis, com separacao corta-fogo, podem manter a alimentacao em 110/220 Vca (Ex.: Escadas Enclausuradas).', NULL, 'item', true, 7),
  ('d244510c-fcba-59ca-bb2e-e218b220ef6e', '3026bfd3-0ea6-5d01-83ce-f904eb7cc0b3', '1', 'Desligar a alimentacao do GMG verificando o arranque automatico de funcionamento do sistema de iluminacao de emergencia.', NULL, 'item', true, 1),
  ('ab305436-e201-5516-8e70-5fc5ce88fda0', '3026bfd3-0ea6-5d01-83ce-f904eb7cc0b3', '2', 'Verificar a comutacao do estado de vigilia (supervisao) para o estado de funcionamento da iluminacao de emergencia ocorre automaticamente em um tempo nao superior a 12 s.', NULL, 'item', true, 2),
  ('4bb15439-55cb-5730-bc19-2ebd818acbab', '3026bfd3-0ea6-5d01-83ce-f904eb7cc0b3', '3', 'Verificar a comutacao do estado de funcionamento para o estado de vigilia (supervisao) da iluminacao de emergencia automaticamente.', NULL, 'item', true, 3),
  ('ecac80d3-d067-5e04-bda0-28cf82c1642c', '3026bfd3-0ea6-5d01-83ce-f904eb7cc0b3', '4', 'Verificar se o sistema mantem iluminacao constante por no minimo 10 minutos com todas as luminarias em funcionamento.', NULL, 'item', true, 4),
  ('d81f8a52-bf94-53d5-b0d7-bb473a2ec44a', 'c275c8db-4142-577d-bd91-5b571f2e84da', '1', 'Verificar se os blocos autonomos/luminarias de emergencia estao devidamente fixados.', NULL, 'item', true, 1),
  ('96a26b85-b3d8-5b0f-a5ea-c6c5f9b385f1', 'c275c8db-4142-577d-bd91-5b571f2e84da', '2', 'Verificar se as luminarias de emergencia estao na posicao "on" (ligadas).', NULL, 'item', true, 2),
  ('dafcabd7-aa12-5021-9d13-7e13fdb34990', 'c275c8db-4142-577d-bd91-5b571f2e84da', '3', 'Verificar se os blocos autonomos funcionam com tensao inferior a 30 Vcc.', NULL, 'item', true, 3),
  ('d2878f8e-e5c2-51bb-bd9f-933f6223e27d', 'c275c8db-4142-577d-bd91-5b571f2e84da', '4', 'Verificar se a conexao eletrica de alimentacao dos blocos autonomos/luminarias de emergencia esta ligada a rede geral de distribuicao de energia da edificacao.', NULL, 'item', true, 4),
  ('0e176d3c-6547-5ed8-a168-c1fe7940e3d6', '8f85eab2-6a8b-5f2e-8d5e-6479034079d6', '1', '1a Possibilidade: Verificar, com o corte geral da rede eletrica, se ocorre o funcionamento de todas as luminarias.', NULL, 'item', true, 1),
  ('5b236cc4-45e5-5d91-a2c6-9279f5c688d1', '8f85eab2-6a8b-5f2e-8d5e-6479034079d6', '2', '2a Possibilidade: Verificar, com o corte do circuito eletrico exclusivo das luminarias de emergencia, se ocorre o funcionamento de todas as luminarias.', NULL, 'item', true, 2),
  ('039ee7de-402d-5b57-8c47-6b9cc1141990', '8f85eab2-6a8b-5f2e-8d5e-6479034079d6', '3', '3a Possibilidade: Verificar, com o desligamento pontual e manual das luminarias de emergencia (retirada de plugues de alimentacao da tomada da rede eletrica), o funcionamento de todas as luminarias. Nota 01: Para esta possibilidade os blocos autonomos deverao estar conectados a tomadas de energia eletrica atraves de seus plugues. Nota 02: A quantidade minima de luminarias de emergencia a serem verificadas devera ser de 20 unidades, procurando alternar pavimentos, caso existam.', NULL, 'item', true, 3),
  ('f1b7ca27-d5ee-5242-b993-83591098d640', '8f85eab2-6a8b-5f2e-8d5e-6479034079d6', '4', 'Verificar, independente das possibilidades citadas acima, se o conjunto de blocos autonomos mantem iluminacao constante por, no minimo, 15 minutos.', NULL, 'item', true, 4),
  ('4184bd2b-537c-5a48-8a23-54c113dce88d', 'df6fd750-d56f-508d-949a-d9ed7511507f', '1', 'Verificar a posicao das luminarias de emergencia nos corredores de acesso conforme indicado em projeto.', NULL, 'item', true, 1),
  ('6544301a-38d6-5587-aae7-2673eb97befe', 'df6fd750-d56f-508d-949a-d9ed7511507f', '2', 'Verificar a posicao das luminarias de emergencia nas escadas conforme indicado em projeto.', NULL, 'item', true, 2),
  ('8ce60bb4-344a-55a5-aa12-e3ba0f3b1b41', 'df6fd750-d56f-508d-949a-d9ed7511507f', '3', 'Verificar a posicao das luminarias de emergencia nas rampas conforme indicado em projeto.', NULL, 'item', true, 3),
  ('f61782cb-0950-5427-aa55-c3b080e2d01b', 'df6fd750-d56f-508d-949a-d9ed7511507f', '4', 'Verificar a posicao das luminarias de emergencia nas descargas conforme indicado em projeto.', NULL, 'item', true, 4),
  ('6b92a338-1fab-55c5-b2ab-d0695a4fef90', 'df6fd750-d56f-508d-949a-d9ed7511507f', '5', 'Verificar a instalacao das luminarias de emergencia nos locais de reuniao de publico (acima de 50 pessoas) conforme indicado em projeto.', NULL, 'item', true, 5),
  ('4d5e001b-6c88-575e-b335-03b2a8f131e8', 'df6fd750-d56f-508d-949a-d9ed7511507f', '6', 'Verificar se as luminarias de emergencia nao provocam o ofuscamento as vistas das pessoas ou das equipes de bombeiro. Nota: O vistoriador devera se atentar para a intensidade luminosa dos projetores e farois.', NULL, 'item', true, 6),
  ('9d86d953-501a-5131-af85-9990d8a6047e', 'df6fd750-d56f-508d-949a-d9ed7511507f', '7', 'Verificar se as luminarias de emergencia estao devidamente fixadas de forma a impedir sua avaria ou remocao acidentais.', NULL, 'item', true, 7),
  ('cc3c7804-87dc-5e84-8a82-9c33523ebeeb', '01fddd18-6f85-542d-bfab-1c88279a0954', '1', 'Conferir se o profissional ou empresa responsavel pela emissao da ART/RRT esta cadastrado na Gerencia de Normas e Cadastro (GNC) para realizar a manutencao.', NULL, 'item', true, 1),
  ('75d5d682-c393-5a37-aafb-59428d772bb4', '91686a91-11fb-5384-9f1f-64ac17b3bc0d', '1', 'Recolher a ART/RRT de manutencao da medida de seguranca Iluminacao de Emergencia.', NULL, 'item', true, 1),
  ('f1f4cddc-a99a-5cf6-9e7f-cf8b679e0fc7', '91686a91-11fb-5384-9f1f-64ac17b3bc0d', '2', 'Conferir na ART/RRT de manutencao da medida de seguranca Iluminacao de Emergencias e os dados da edificacao vistoriada conferem com os dados mencionados no documento.', NULL, 'item', true, 2),
  ('e97fbed6-d7b5-510d-b811-62c9872a0813', '91686a91-11fb-5384-9f1f-64ac17b3bc0d', '3', 'Conferir na que toda a ART/RRT possua no campo "Observacoes" a seguinte descricao: "As manutencoes e servicos de Iluminacao de Emergencia foram executados conforme parte II da IT 05".', NULL, 'item', true, 3),
  ('2aae02cb-b9d6-5fca-9079-a08b0a6a41d6', '91686a91-11fb-5384-9f1f-64ac17b3bc0d', '4', 'Conferir a autenticidade da ART/RRT mediante assinatura', NULL, 'item', true, 4),
  ('e267274c-4a2f-5b9e-b425-d37f6a5401cb', '5631b322-c229-563b-a837-98da7b740889', '1', 'Recolher, quando for o caso, as notas fiscais dos componentes, equipamentos e servicos utilizados na medida de seguranca de Iluminacao de Emergencia (Baterias, geradores, painel de controle, blocos autonomos, luminarias, etc).', NULL, 'item', true, 1),
  ('78a7bf69-c9ff-53be-9fb4-d60fcdb32237', 'd4b156a1-61e9-5279-8891-a184726c913f', '1', 'Solicitar, quando de novas instalacoes, documentacao que comprove a garantia do fabricante de no minimo dois anos para as baterias utilizadas nos sistema deIe por Central de baterias recarregaveis e nos blocos autonomos.', NULL, 'item', true, 1),
  ('ceac60c0-2395-5df5-995a-4fa3e40f699f', '29b3c3b1-5cc0-5566-bac9-dbad8b5383dc', '1', 'Verificar nas areas de risco especificas (deposito de explosivo, postosde combustiveis, etc) a necessidade das devidas sinalizacoes de proibicao atentando para os checklists especificos.', NULL, 'item', true, 1),
  ('aca3eb52-c53c-5e17-b0b0-8ab9eff6623d', 'e6bf611f-93c4-5c69-a1a4-b5d34f811eed', '1', 'Verificar nas areas de risco especificas (deposito de explosivo, postos de combustiveis, etc) a necessidade das devidas sinalizacoes de alerta atentando para os checklists especificos.', NULL, 'item', true, 1),
  ('b2e1e4cd-f91d-5836-99e6-00083ad6455d', 'bfd51c13-5fc6-5e5d-8176-8f790e6595c9', '1', 'Verificar o atendimento da sinalizacao de emergencia de equipamentos conforme checklist de cada medida de seguranca, quando for o caso.', NULL, 'item', true, 1),
  ('5e558ed7-4240-557a-8ab7-b2725468e5da', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '1', 'Verificar, a partir dos pontos de distancia mais desfavoraveis (maior SMTP), se as sinalizacoes de emergencia estao corretamente orientadas para as rotas fugas principais(escadas,rampas) ou area externa, quando localizada em pavimento terreo.', NULL, 'item', true, 1),
  ('00621dc2-c1f6-52af-bbc1-aeb7b05f8bd6', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '2', 'Verificar se os pictogramas das sinalizacoes de emergencia das saidas de emergencia sao compativeis com a parte III da IT 05 (codigos S1 a S21 da parte III da IT 05).', NULL, 'item', true, 2),
  ('0207ef91-cefb-5026-86a7-6033688ed849', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '3', 'Verificar,dentro da sunidade sautonomas (salas,auditorios,cinemas,etc) com compatibilidade da fixacao das sinalizacoes de emergencia para orientacao de fuga (sinalizacoes com codigos de S1 ao S3).', NULL, 'item', true, 3),
  ('c41f69ba-d29d-5f48-a03e-399390defd5c', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '4', 'Verificar, nos corredores/halls de acesso, a existencia e compatibilidade da fixacao das sinalizacoes de emergencia para orientacao de fuga. (sinalizacoes com codigos S1 ao S3).', NULL, 'item', true, 4),
  ('99a7b2bc-8855-52c2-8179-7071c5191937', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '5', 'Verificar nos acessos as escadas e rampas a existencia e compatibilidade da fixacao das sinalizacoes de emergencia para orientacao de fuga. (sinalizacoes com codigos de S4 ao S9).', NULL, 'item', true, 5),
  ('5307a964-8e2e-5f7c-8945-2b18507b94f4', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '6', 'Verificar nas descargas a existencia e compatibilidade da fixacao das sinalizacoes de emergencia para orientacao de fuga (sinalizacoes com codigos de S12 ao S16).', NULL, 'item', true, 6),
  ('2d0e2bc3-2aa0-5c84-90c0-0a0fb705401d', '9a607c3e-bdb5-5856-b0a7-538b666542b3', '7', 'Verificar, para os recintos destinados a reuniao de publico da divisao F-5 e F-6 cujas atividades se desenvolvem sem aclaramento natural, se a sinalizacao de emergencia e do tipo luminarias de balizamento com a indicacao de saida (mensagem escrita e/ou simbolo correspondente conforme codigos previstos na parte III da IT 05 e requisitos de funcionamento conforme ABNT NBR 10898).', NULL, 'item', true, 7),
  ('8a6312bd-d97f-59c5-9c76-267202e3704e', '1a938af9-e098-5e42-842c-ce2f640d6bc5', NULL, 'Verificar no acesso principal dos recintos destinados ar euniao de publico das divisoes F-3, F-5, F-6 e F-7, sinalizacao que indique a capacidade maxima de publico admitida para o estabelecimento.', NULL, 'item', true, 1),
  ('23243bff-26ab-5765-91b2-35ca4703a93c', '63f7e822-4ce7-5edf-9c39-d98d90f57c80', '1', 'Verificar se o tamanho das placas de sinalizacao de emergencia das saidas de emergencia e compativel com a distancia de visualizacao - (Tabela 1 do Anexo A da parte III da IT 05, exemplos: - Distancia de visualizacao/Largura:8m/179mm. - Distancia de visualizacao/Largura:10m/224mm. - Distancia de visualizacao/Largura:14m/313mm. - Distancia de visualizacao/Largura:20m/447mm. - Distancia de visualizacao/Largura:30m/671mm).', NULL, 'item', true, 1),
  ('c12a5677-6089-5066-b1a1-edc1f80a5ecc', '63f7e822-4ce7-5edf-9c39-d98d90f57c80', '2', 'Verificar, quando possivel, se as sinalizacoes de emergencia possuem espessura minima de 1 mm.', NULL, 'item', true, 2),
  ('7c75212e-7b14-511b-ba94-9689dd5dc687', '63f7e822-4ce7-5edf-9c39-d98d90f57c80', '3', 'Verificar se o pictograma da sinalizacao de emergencia esta de acordo com a parte III da IT 05.', NULL, 'item', true, 3),
  ('33722f01-dc91-5a3f-8ef5-2137812cbce6', '63f7e822-4ce7-5edf-9c39-d98d90f57c80', '4', 'Verificar se a cor de fundo da sinalizacao de emergencia esta de acordo com a parte III da IT 05.', NULL, 'item', true, 4),
  ('4540dab4-e8f9-56a3-bd16-977b3c91125c', '63f7e822-4ce7-5edf-9c39-d98d90f57c80', '5', 'Verificar se as sinalizacoes de emergencia possuem na borda inferior direita a descricao do fabricante (Razao Social ou CNPJ) e as caracteristicas do ensaio de efeitos fotoluminescente (Ex.:427/20,3-1800 - K - W) com o devido simbolo da empresa certificadora.', NULL, 'item', true, 5),
  ('30d5f36c-ea2e-51f7-b05f-d8d83aa6c87c', 'dbae2d06-3235-5e5b-a216-23d6ce2b0250', '1', 'Verificar se as sinalizacoes de emergencia estao devidamente fixadas (coladas/parafusadas).', NULL, 'item', true, 1),
  ('5ade4c57-692b-5b4c-85e9-5e5a069fce7a', 'dbae2d06-3235-5e5b-a216-23d6ce2b0250', '2', 'Verificar se as sinalizacoes de emergencia estao fixadas a uma altura minima de 1,80m. Nota: Para os locais de reuniao de publico (F-5 e F-6) as sinalizacoes deverao estar fixadas e visiveis, podendo estas, estar em alturas superiores as recomendadas em norma (1,80m) de forma que possam ser vistas pelo publico.', NULL, 'item', true, 2),
  ('a98d68b8-40df-5aef-b271-a7e671fb3c6f', '7f683fc5-eabc-5c50-8bce-fce584dc09f1', '1', 'Verificar se a empresa instaladora das sinalizacoes de emergencia possui cadastro na Gerencia de Normas e Cadastros (GNC).', NULL, 'item', true, 1),
  ('7a8fc366-6e11-58f6-99fa-921abed6e52d', '7f683fc5-eabc-5c50-8bce-fce584dc09f1', '2', 'Recolher notas fiscais das sinalizacoes de emergencia.', NULL, 'item', true, 2),
  ('a9d3dce6-ccf1-519d-8971-b20b776ccd65', '6717f4a8-9576-5205-9c3a-9acb6bb2787b', '1', 'Verificar se os extintores estao localizados nas posicoes definidas em planta.', NULL, 'item', true, 1),
  ('6ee565df-3407-5fd0-aed2-90f1ae4cab76', '6717f4a8-9576-5205-9c3a-9acb6bb2787b', '2', 'Verificar se o agente extintor do extintor esta conforme especificado em planta.', NULL, 'item', true, 2),
  ('b1fd7856-9e6d-5088-98ff-b29bfd831bf4', '6717f4a8-9576-5205-9c3a-9acb6bb2787b', '3', 'Verificar se a capacidade extintora esta conforme especificada em planta.', NULL, 'item', true, 3),
  ('8d9a1a97-f3bf-548a-a264-86cd5f4c6c9f', '6717f4a8-9576-5205-9c3a-9acb6bb2787b', '4', 'Verificar se os extintores estao fixados em colunas, paredes ou divisorias, de maneira que sua parte superior (gatilho) fique a uma altura maxima de 1,60m (um metro e sessenta centimetros) do piso acabado, podendo ser disposto sobre suporte apropriado com altura de 0,20 m.', NULL, 'item', true, 4),
  ('66ae464c-35ef-5494-9ddd-da25122e26d8', '6717f4a8-9576-5205-9c3a-9acb6bb2787b', '5', 'Verificar, para extintores sobrerrodas, se a sua localizacao esta na area a ser protegida definida em planta.', NULL, 'item', true, 5),
