  ('2f7aa902-c866-5030-b9b2-f1e774c9db64', '0412d689-bd03-523d-b2d9-67f8ef1574ae', '2', 'Verificar na casa de bombas se esta instalado placa de identificacao para as Bombas Eletricas de Incendio com as seguintes informacoes: Nome do fabricante, no de serie, modelo, vazao nominal, pressao nominal, rotacao de funcionamento, diametro do rotor e potencia eletrica do motor.', NULL, 'item', true, 2),
  ('385894f9-271e-5e1b-9602-cb6435f48375', '0412d689-bd03-523d-b2d9-67f8ef1574ae', '3', 'Verificar na casa de bombas se esta instalado placa de identificacao para as Bombas de Incendio a Diesel, quando houver, com as seguintes informacoes: Nome do fabricante, no de serie, modelo, potencia e rotacao de funcionamento.', NULL, 'item', true, 3),
  ('fa247d78-fcef-5ac7-8d9d-eeeaea3b6f5e', '0412d689-bd03-523d-b2d9-67f8ef1574ae', '4', 'Verificar se esta instalado placa de identificacao para todas as VGA''s e VCS''s.', NULL, 'item', true, 4),
  ('f86c7d15-3777-5001-a72c-f0e089c5ba8c', 'f255195e-88f8-5640-8d9b-7a28d431d1d9', '1', 'Verificar se a posicao do hidrante de recalque esta conforme indicada em planta (passeio publico).', NULL, 'item', true, 1),
  ('6183b272-6c8a-5be2-89e6-cd0f18b747f0', 'f255195e-88f8-5640-8d9b-7a28d431d1d9', '2', 'Verificar se a tampa do abrigo possui a inscricao "INCENDIO".', NULL, 'item', true, 2),
