  ('f26bdf45-2359-50d1-b2fa-95e108762b1f', '6b5e6e16-8092-536e-b480-b26bb8df5092', '2', 'Verificar se com a "total abertura" da valvula teste da VGA a BCI entra em funcionamento e ocorre o desligamento automatico da bomba de pressurizacao (joquei).', NULL, 'item', true, 2),
