  ('cbe73b0b-1e5c-5c64-9efc-fca00e1d2200', '2c8b5a30-dc57-50fc-8ae9-b21f34da0e28', '11', 'Verificar se a central de gas possui os extintores conforme indicado em planta.', NULL, 'item', true, 11),
